const{atividades,addAtividade}=useAtividades(lead.id,clienteId);const connectedSdrs=equipe.filter(m=>m.waha_session&&m.waha_connected);const defaultSession=connectedSdrs.find(s=>s.nome===lead.sdr_nome)?.waha_session||connectedSdrs[0]?.waha_session||"pedro-oliveira";
